+            }
+        }
+        std::hint::black_box(sum)
+    };
+
+    // Measure with 1 worker.
+    let tasks_1 = build_pipeline_tasks(PipelineId(0), PipelineKind::ScanFilterProject, &morsels);
+    let d1 = WorkStealingDispatcher::try_new(DispatcherConfig {
+        worker_threads: 1,
