+        let mut e = DpEngine::new(0.5, 42).unwrap();
+        e.laplace(100.0, 1.0, 0.5).unwrap();
+        let pass = e.laplace(100.0, 1.0, 0.1).is_err();
+        results.push(TestResult {
+            name: "budget_exhaustion",
