+
+    // Readers verify consistency.
+    let readers: Vec<_> = (0..4)
+        .map(|_| {
+            let rlr = Arc::clone(&lr);
+            let rs = Arc::clone(&stop);
+            let rb = Arc::clone(&barrier);
