+    let depth = 4;
+    let fanout = 16;
+    let num_lookups = 500_000;
+    let (pages, root) = build_sim_btree(depth, fanout);
+    let num_pages = pages.len();
+
+    let page_table: HashMap<u64, usize> =
+        (0..num_pages as u64).map(|pid| (pid, pid as usize)).collect();
