+    println!("  depth:       {}", if pass_depth { "PASS" } else { "FAIL" });
+    println!("  [{passed}/{total_count}] conformance checks passed");
+
+    assert_eq!(
+        passed, total_count,
+        "bead_id={BEAD_ID} conformance={passed}/{total_count}"
+    );
+}

