+#[test]
+fn frame_batch_commit_detection() {
+    // Non-commit batch: db_size_if_commit == 0 on all frames.
+    let frames = vec![FrameSubmission {
+        page_number: 1,
+        page_data: vec![0u8; 4096],
+        db_size_if_commit: 0,
+    }];
+    let batch = TransactionFrameBatch::new(frames);
