+    assert!(!batch.has_commit_frame());
+
+    // Commit batch: last frame has db_size > 0.
+    let frames = vec![
+        FrameSubmission {
+            page_number: 1,
+            page_data: vec![0u8; 4096],
+            db_size_if_commit: 0,
+        },
+        FrameSubmission {
+            page_number: 2,
+            page_data: vec![0u8; 4096],
+            db_size_if_commit: 100,
+        },
+    ];
+    let batch = TransactionFrameBatch::new(frames);
+    assert_eq!(batch.frame_count(), 2);
+    assert!(batch.has_commit_frame());
