+// ── 10. Group commit metrics (parallel WAL) ─────────────────────────────────
+
+#[test]
+fn group_commit_metrics_fsync_reduction() {
+    let metrics = GroupCommitMetrics::new();
+
+    // Simulate 32 individual submissions batched into 4 group commits.
+    for _ in 0..32 {
+        metrics.record_submission();
+    }
+    for i in 0..4u64 {
